class Solution:
    def maxScore(self, cardPoints, k):
        n = len(cardPoints)
        total = sum(cardPoints)
        w = n - k
        if w == 0:
            return total
        win = sum(cardPoints[:w])
        min_win = win
        for i in range(w, n):
            win += cardPoints[i] - cardPoints[i - w]
            min_win = min(min_win, win)
        return total - min_win

